from dataclasses import dataclass
from datetime import date

@dataclass
class LessonsVerification:
    postmortem_id: str
    lesson_score: int
    rollout_date: date
    verification_date: date

    # Evidence gathered at 60-day check
    runbook_updated_in_sister_teams: bool
    similar_incident_in_window: bool
    similar_incident_handled_better: bool | None  # None if no similar incident
    game_day_result: str | None  # None if no game day was run; "passed" | "failed" | "partial"

    def knowledge_landed(self) -> bool:
        if not self.runbook_updated_in_sister_teams:
            return False
        if self.game_day_result == "failed":
            return False
        if self.similar_incident_in_window and self.similar_incident_handled_better is False:
            return False
        return True

    def remediation_needed(self) -> list[str]:
        actions = []
        if not self.runbook_updated_in_sister_teams:
            actions.append("Follow up with sister team EMs on runbook update — not yet applied")
        if self.game_day_result == "failed":
            actions.append("Game day failed — schedule a repeat exercise after reviewing the failure")
        if self.similar_incident_in_window and self.similar_incident_handled_better is False:
            actions.append("Similar incident was not handled better — re-run sister-team briefing")
        return actions

from dataclasses import dataclass
from enum import Enum
from datetime import date

class SensitivityLevel(str, Enum):
    STANDARD         = "standard"
    RESTRICTED       = "restricted"   # limited to specific teams
    LEGAL_HOLD       = "legal_hold"   # no rollout until hold is released
    SAFETY_TRACK     = "safety_track" # Policy + RSP team first; then standard

@dataclass
class LessonSensitivity:
    postmortem_id: str
    level: SensitivityLevel
    restriction_reason: str | None
    approved_audiences: list[str]    # empty = standard (all engineers)
    legal_hold_released_at: date | None = None

    def can_rollout_to(self, audience: str) -> bool:
        if self.level == SensitivityLevel.LEGAL_HOLD:
            if self.legal_hold_released_at is None:
                return False
        if self.approved_audiences and audience not in self.approved_audiences:
            return False
        return True

    def rollout_blocked_reason(self, audience: str) -> str | None:
        if self.level == SensitivityLevel.LEGAL_HOLD and self.legal_hold_released_at is None:
            return "Legal hold is active — no rollout until released"
        if self.approved_audiences and audience not in self.approved_audiences:
            return f"Audience '{audience}' not in approved list for this lesson"
        return None
